import fs from 'fs';
import path from 'path';

const fileArg = process.argv[2];

if (!fileArg) {
  console.error('Error: Please provide the path to repo-context.json');
  process.exit(1);
}

const filePath = path.resolve(process.cwd(), fileArg);

try {
  const fileContent = fs.readFileSync(filePath, 'utf8');
  const data = JSON.parse(fileContent);

  if (!data.path) {
    console.error('Error: repo-context.json is missing the "path" field.');
    process.exit(1);
  }

  if (!Array.isArray(data.whitelist)) {
    console.error('Error: repo-context.json "whitelist" must be an array.');
    process.exit(1);
  }

  console.log('✅ repo-context.json is valid!');
  process.exit(0);
} catch (error) {
  console.error(`Error reading or parsing ${fileArg}:`, error.message);
  process.exit(1);
}
